.darma-loader-darma-custom-405 {color: var(--loader-color, #2563eb);
  --loader-secondary-color: var(--loader-secondary-color, #38bdf8);
  --loader-bg: var(--loader-bg, #ffffff);
  width: 90px;
  height: 24px;
  padding: 2px 0;
  box-sizing: border-box;
  display: flex;
  animation: darma-loader-darma-custom-405-l5-0 3s infinite steps(6);
  background:linear-gradient(currentColor 0 0) 0 0/0% 100% no-repeat,radial-gradient(circle 3px,#eeee89 90%,#0000) 0 0/20% 100% currentColor;
  overflow: hidden;
}.darma-loader-darma-custom-405::before {content: "";
  width: 20px;
  transform: translate(-100%);
  border-radius: 50%;
  background: #ffff2d;
  animation:darma-loader-darma-custom-405-l5-1 .25s .153s infinite steps(5) alternate,darma-loader-darma-custom-405-l5-2 3s infinite linear;
}@keyframes darma-loader-darma-custom-405-l5-1{0% {clip-path: polygon(50% 50%,100% 0,100% 0,0 0,0 100%,100% 100%,100% 100%)}100% {clip-path: polygon(50% 50%,100% 65%,100% 0,0 0,0 100%,100% 100%,100% 35%)}}@keyframes darma-loader-darma-custom-405-l5-2{100% {transform: translate(90px)}}@keyframes darma-loader-darma-custom-405-l5-0{100% {background-size:120% 100%,20% 100%}}

